"import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const scratchDir = __dirname;
const outputDir = path.join(scratchDir, 'restored_code');

if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

function cleanFile(fileName) {
  const filePath = path.join(scratchDir, fileName);
  if (!fs.existsSync(filePath)) {
    console.log(`File not found: ${fileName}`);
    return;
  }
  const content = fs.readFileSync(filePath, 'utf8');
  const lines = content.split('\n');
  const cleanedLines = [];

  let started = false;
  for (const line of lines) {
    // Look for lines starting with a number and a colon, e.g. "3440: some code"
    const match = line.match(/^\s*(\d+):(.*)$/);
    if (match) {
      started = true;
      const code = match[2];
      cleanedLines.push(code);
    } else {
      // If we already started reading code lines, and hit a line that doesn't match,
      // it might be a line wrapped or blank line in log, but let's be careful.
      // Usually, every line of the file in VIEW_FILE has a line number prefix.
    }
  }

  if (cleanedLines.length > 0) {
    const outPath = path.join(outputDir, fileName.replace('_view_file.txt', '_clean.tsx'));
    fs.writeFileSync(outPath, cleanedLines.join('\n'), 'utf8');
    console.log(`Cleaned ${fileName} -> ${outPath} (${cleanedLines.length} lines)`);
  } else {
    console.log(`No line-numbered lines found in ${fileName}`);
  }
}

const filesToClean = [
  'step_856_view_file.txt',
  'step_860_view_file.txt',
  'step_752_view_file.txt',
  'step_846_view_file.txt',
  'step_826_view_file.txt'
];

filesToClean.forEach(cleanFile);
"
